// RoPE embedding backward with attention scaling — CUDA kernel.
//
// grad_position_ids[b,s] = sum_{d=0}^{63} inv_freq[b,d] * (
//     (gc[b,s,d] + gc[b,s,d+64]) * (-sin(emb[b,s,d])) * scale +
//     (gs[b,s,d] + gs[b,s,d+64]) * ( cos(emb[b,s,d])) * scale )
//
// head_dim=128 const, half_dim=64 const. Strictly memory-bound
// (AI ~0.56 FLOP/byte): the whole op is one read-256B*3-write-4B streaming
// reduction per output row. The Triton frontier (0.885) plateaued after
// exhausting BLOCK_M/BLOCK_D/eviction/num_stages autotune; the remaining
// lever is achieved HBM bandwidth%, which needs a memory access pattern
// Triton's codegen doesn't reach.
//
// Design: one WARP per output row (b,s). Each of the 32 lanes owns 2 of the
// 64 half_dim elements (lane, lane+32) so every load across the warp is a
// single contiguous 32-lane transaction (64B for bf16, 128B for fp32) —
// fully coalesced, no wasted sectors. Partial sums reduce via
// __shfl_down_sync (5 steps), lane 0 writes the row's scalar output. This
// avoids the previous attempt's one-thread-per-row layout, whose per-thread
// row stride (256B) serialized every warp into 32 separate transactions.
//
// sin/cos are computed in double and rounded down to float: nvcc's
// --use_fast_math (if applied by the harness's default compile_options)
// only swaps single-precision transcendentals for the fast SFU intrinsics
// (__sinf/__cosf) — there is no fast-math double path, so this keeps the
// reference-matching accuracy regardless of compile flags, at negligible
// cost (compute is ~200x cheaper than the memory traffic here).

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAException.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <math.h>

#define HEAD_DIM 128
#define HALF_DIM 64
#define WARPS_PER_BLOCK 8
#define THREADS_PER_BLOCK (WARPS_PER_BLOCK * 32)

__global__ void __launch_bounds__(THREADS_PER_BLOCK)
rope_bwd_kernel(
    const __nv_bfloat16* __restrict__ grad_cos,   // (B, S, 128)
    const __nv_bfloat16* __restrict__ grad_sin,   // (B, S, 128)
    const float* __restrict__ emb,                // (B, S, 128); only [..., :64] read
    const float* __restrict__ inv_freq,           // (B, 64)
    float* __restrict__ out,                      // (B, S) flattened
    long long total_rows,
    long long S,
    float scale)
{
    const long long global_warp =
        (long long)blockIdx.x * WARPS_PER_BLOCK + (threadIdx.x >> 5);
    if (global_warp >= total_rows) return;
    const int lane = threadIdx.x & 31;

    const long long b = global_warp / S;

    const long long row_off = global_warp * (long long)HEAD_DIM;
    const __nv_bfloat16* gc_row = grad_cos + row_off;
    const __nv_bfloat16* gs_row = grad_sin + row_off;
    const float* emb_row = emb + row_off;
    const float* inv_row = inv_freq + b * HALF_DIM;

    float acc = 0.0f;
    #pragma unroll
    for (int k = 0; k < 2; k++) {
        const int d = lane + k * 32;  // lanes 0..31 -> d in {0..31} then {32..63}

        const float gc = __bfloat162float(gc_row[d]) +
                          __bfloat162float(gc_row[d + HALF_DIM]);
        const float gs = __bfloat162float(gs_row[d]) +
                          __bfloat162float(gs_row[d + HALF_DIM]);

        const double e = (double)emb_row[d];
        const float sin_v = (float)sin(e);
        const float cos_v = (float)cos(e);

        // Same left-to-right op order as the reference: (gc*(-sin))*scale + (gs*cos)*scale
        const float grad_emb = gc * (-sin_v) * scale + gs * cos_v * scale;
        acc += grad_emb * inv_row[d];
    }

    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        acc += __shfl_down_sync(0xFFFFFFFFu, acc, offset);
    }

    if (lane == 0) {
        out[global_warp] = acc;
    }
}

torch::Tensor run(
    torch::Tensor grad_cos,
    torch::Tensor grad_sin,
    torch::Tensor emb,
    torch::Tensor inv_freq_expanded,
    double attention_scaling)
{
    grad_cos = grad_cos.contiguous();
    grad_sin = grad_sin.contiguous();
    emb = emb.contiguous();
    inv_freq_expanded = inv_freq_expanded.contiguous();

    TORCH_CHECK(grad_cos.is_cuda(), "grad_cos must be CUDA");
    TORCH_CHECK(grad_cos.scalar_type() == torch::kBFloat16, "grad_cos must be bf16");
    TORCH_CHECK(grad_sin.scalar_type() == torch::kBFloat16, "grad_sin must be bf16");
    TORCH_CHECK(emb.scalar_type() == torch::kFloat32, "emb must be float32");
    TORCH_CHECK(inv_freq_expanded.scalar_type() == torch::kFloat32,
                "inv_freq_expanded must be float32");

    const long long B = grad_cos.size(0);
    const long long S = grad_cos.size(1);
    const long long total_rows = B * S;

    auto out = torch::empty({B, S}, emb.options());

    if (total_rows == 0) {
        return out;
    }

    const float scale = static_cast<float>(attention_scaling);

    const __nv_bfloat16* gc_ptr =
        reinterpret_cast<const __nv_bfloat16*>(grad_cos.data_ptr());
    const __nv_bfloat16* gs_ptr =
        reinterpret_cast<const __nv_bfloat16*>(grad_sin.data_ptr());
    const float* emb_ptr = emb.data_ptr<float>();
    const float* inv_ptr = inv_freq_expanded.data_ptr<float>();
    float* out_ptr = out.data_ptr<float>();

    cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();

    const long long blocks = (total_rows + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    rope_bwd_kernel<<<(unsigned int)blocks, THREADS_PER_BLOCK, 0, stream>>>(
        gc_ptr, gs_ptr, emb_ptr, inv_ptr, out_ptr,
        total_rows, S, scale);
    C10_CUDA_KERNEL_LAUNCH_CHECK();

    return out;
}

// Insurance overload: some harness paths may pass attention_scaling as a 0-d tensor.
torch::Tensor run_tensor_scale(
    torch::Tensor grad_cos,
    torch::Tensor grad_sin,
    torch::Tensor emb,
    torch::Tensor inv_freq_expanded,
    torch::Tensor attention_scaling)
{
    return run(grad_cos, grad_sin, emb, inv_freq_expanded,
               attention_scaling.item<double>());
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "RoPE embedding backward with attention scaling (scalar scale)");
    m.def("run", &run_tensor_scale, "RoPE embedding backward with attention scaling (tensor scale)");
}

